import React from 'react';
import { Link } from 'gatsby';
import HorizontalPan from '@containers/HorizontalPan';
import { LinkButton } from '@components/ui/Button';
import * as styles from './footer.module.css';

export default function Footer() {
	return (
		<footer id={styles.ftr}>
			<HorizontalPan panOnTouchDeviceOnly={true} className={styles.ftrRow}>
				<div>
					<h3>Product</h3>
					<ul>
						<li>
							<Link activeClassName="active" to="/product">
								About Darkkpool AI
							</Link>
						</li>
						<li>
							<Link activeClassName="active" to="/pricing">
								Pricing
							</Link>
						</li>
						<li>
							<Link activeClassName="active" to="/about">
								About Us
							</Link>
						</li>
						{/* <li>
							<Link activeClassName="active" to="/terms-of-use">
								Terms Of Use
							</Link>
						</li> */}
					</ul>
				</div>
				<div>
					<h3>More</h3>
					<ul>
						<li>
							<Link activeClassName="active" to="/privacy-policy">
								Privacy Policy
							</Link>
						</li>
						{/* <li>
							<Link activeClassName="active" to="/cookie-policy">
								Cookie Policy
							</Link>
						</li> */}
						<li>
							<Link activeClassName="active" to="/pricing#frequently-asked-questions">
								FAQs
							</Link>
						</li>
						<li>
							<Link activeClassName="active" to="/contact">
								Contact
							</Link>
						</li>
					</ul>
				</div>
				<ul>
					<li>
						<LinkButton variant="secondary" target="_blank" to="https://t.me/Lunaticnifty50_bot">
							Access Tool
						</LinkButton>
					</li>
					<li>
						<LinkButton variant="tertiary" to="/product">
							Learn More
						</LinkButton>
					</li>
				</ul>
			</HorizontalPan>
			<div>copyright &copy; 2024, darkkpool.ai</div>
		</footer>
	);
}
